// source: snippets/business-hours.js
// Is-now-within-BUSINESS_HOURS check for WF-H (spec E6 Req 3). Reads only
// `$env.BUSINESS_HOURS` + `$env.BUSINESS_TZ` — no per-tenant hours exist in the
// schema (confirmed: grep of sql/ + backend/ for business_hours is empty), so
// this is a single global window, not per-tenant.
//
// BUSINESS_HOURS format: "HH:MM-HH:MM" (every day) or "DDD-DDD HH:MM-HH:MM"
// (day range, e.g. "MON-FRI 09:00-18:00"). Wraps past midnight if start > end.
// An unparseable value fails OPEN (never silently swallows a real escalation —
// off-hours only suppresses the on-call ping, it never drops the alert).
function isWithinBusinessHours(now, businessHours, businessTz) {
  const spec = String(businessHours || "").trim();
  const match = spec.match(/^(?:([A-Za-z]{3})-([A-Za-z]{3})\s+)?(\d{2}):(\d{2})-(\d{2}):(\d{2})$/);
  if (!match) return true;

  const [, dayFrom, dayTo, h1, m1, h2, m2] = match;
  const tz = businessTz || "UTC";

  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: tz,
    weekday: "short",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).formatToParts(now);
  const get = (type) => parts.find((p) => p.type === type)?.value || "";

  const DAYS = ["SUN", "MON", "TUE", "WED", "THU", "FRI", "SAT"];
  const weekday = get("weekday").toUpperCase().slice(0, 3);
  const hour = parseInt(get("hour"), 10) % 24; // Intl can return "24" for midnight
  const minute = parseInt(get("minute"), 10);
  const minutesNow = hour * 60 + minute;
  const minutesStart = parseInt(h1, 10) * 60 + parseInt(m1, 10);
  const minutesEnd = parseInt(h2, 10) * 60 + parseInt(m2, 10);

  let inDayRange = true;
  if (dayFrom && dayTo) {
    const from = DAYS.indexOf(dayFrom.toUpperCase());
    const to = DAYS.indexOf(dayTo.toUpperCase());
    const cur = DAYS.indexOf(weekday);
    if (from === -1 || to === -1 || cur === -1) return true; // fail open
    inDayRange = from <= to ? cur >= from && cur <= to : cur >= from || cur <= to;
  }

  const inTimeRange =
    minutesStart <= minutesEnd
      ? minutesNow >= minutesStart && minutesNow < minutesEnd
      : minutesNow >= minutesStart || minutesNow < minutesEnd;

  return inDayRange && inTimeRange;
}

function run(items, env) {
  const inBusinessHours = isWithinBusinessHours(new Date(), env.BUSINESS_HOURS, env.BUSINESS_TZ);
  return items.map((item) => ({ json: { ...item.json, inBusinessHours } }));
}

if (typeof $input !== "undefined") {
  return run($input.all(), { BUSINESS_HOURS: $env.BUSINESS_HOURS, BUSINESS_TZ: $env.BUSINESS_TZ });
}

module.exports = { isWithinBusinessHours, run };

// source: snippets/sla-sweep.js
// Hourly ops-sweep classifier for WF-O (spec E10 Req 1). Pure decision logic:
// the two Postgres fetch nodes upstream supply candidates (notified-unassigned
// escalations + needs_human conversations), the Business Hours node has already
// stamped `inBusinessHours` on every item; this decides what gets acted on and
// never touches the DB itself — the guarded marker INSERT / guarded UPDATE
// downstream stay the single writers.
//
// Decisions:
//  * sla_realert — escalation still status='notified' and unassigned after
//    $env.SLA_MINUTES. Emitted on EVERY sweep while stale; the `sla_realert`
//    events marker (006 partial unique index + ON CONFLICT DO NOTHING) is what
//    makes the Slack re-alert fire exactly ONCE per escalation.
//  * abandon — needs_human conversation with NO captured customer_email
//    (nobody to follow up with), idle longer than $env.ABANDON_HOURS, and only
//    OFF-hours (during business hours a quiet needs_human is the agents' queue,
//    not the sweep's). WF-O is the ONLY writer of needs_human→abandoned.
//
// Missing/unparseable env FAILS QUIET for that decision (no realert / no
// abandon): a state transition and a page must never fire off a misconfigured
// threshold. Anything unclassifiable — fresh, assigned, in-hours, has-email,
// or the empty `alwaysOutputData` placeholder item — drops out.
function sweep(items, env, now) {
  const nowMs = (now instanceof Date ? now : new Date(now)).getTime();
  const slaMinutes = parseInt(env.SLA_MINUTES, 10);
  const abandonHours = parseInt(env.ABANDON_HOURS, 10);
  const actions = [];

  for (const item of items) {
    const row = item.json || item;

    if (row.escalation_id && row.notified_at) {
      if (!Number.isFinite(slaMinutes) || slaMinutes <= 0) continue;
      const waitedMinutes = Math.floor((nowMs - new Date(row.notified_at).getTime()) / 60000);
      if (waitedMinutes >= slaMinutes) {
        actions.push({
          json: {
            action: "sla_realert",
            escalation_id: row.escalation_id,
            conversation_id: row.conversation_id,
            tenant_name: row.tenant_name || "(unknown tenant)",
            waited_minutes: waitedMinutes,
          },
        });
      }
    } else if (row.conversation_id && row.last_activity_at) {
      if (!Number.isFinite(abandonHours) || abandonHours <= 0) continue;
      if (row.customer_email) continue;
      if (row.inBusinessHours !== false) continue;
      const idleHours = Math.floor((nowMs - new Date(row.last_activity_at).getTime()) / 3600000);
      if (idleHours >= abandonHours) {
        actions.push({
          json: {
            action: "abandon",
            conversation_id: row.conversation_id,
            tenant_name: row.tenant_name || "(unknown tenant)",
            idle_hours: idleHours,
          },
        });
      }
    }
  }

  return actions;
}

if (typeof $input !== "undefined") {
  return sweep(
    $input.all(),
    { SLA_MINUTES: $env.SLA_MINUTES, ABANDON_HOURS: $env.ABANDON_HOURS },
    new Date(),
  );
}

module.exports = { sweep };

// source: snippets/format-digest.js
// Daily-digest formatter for WF-O (spec E10 Req 1). Pure: turns the three
// upstream fetches (per-tenant stats rows, the one-row account stats, the
// Upstash demo-budget mget response) into one Slack text + one Gmail
// subject/body. Real counts only — a stat the query couldn't produce renders
// as "n/a", never invented. The Upstash call is continueOnFail upstream, so a
// dead Redis shows the budget as "n/a" instead of killing the digest.
function escapeHtml(s) {
  return String(s || "").replace(/[&<>"']/g, (c) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#39;",
  }[c]));
}

function pct(rate) {
  if (rate === null || rate === undefined || rate === "") return "n/a";
  const n = Number(rate);
  return Number.isFinite(n) ? `${Math.round(n * 100)}%` : "n/a";
}

function budgetLine(used, cap) {
  if (used === null || used === undefined) return `n/a of ${cap ?? "?"}`;
  return `${used} of ${cap ?? "?"}`;
}

function formatDigest(tenants, account, budget, env, now) {
  const day = (now instanceof Date ? now : new Date(now || Date.now()))
    .toISOString()
    .slice(0, 10);

  const tenantLines = tenants.length
    ? tenants.map((t) => {
        const head =
          `*${t.tenant_name}* — ${t.conversations_24h ?? 0} conversation(s) in 24h · ` +
          `deflection ${pct(t.deflection_rate)} all-time (${t.total_conversations ?? 0} total) · ` +
          `${t.open_escalations ?? 0} open escalation(s)`;
        return t.top_gaps ? `${head}\n    gaps: ${t.top_gaps}` : head;
      })
    : ["(no tenants yet)"];

  const accountLine =
    `*Accounts:* ${account.trial_signups_24h ?? "n/a"} trial signup(s) · ` +
    `${account.premium_leads_24h ?? "n/a"} premium lead(s) in 24h ` +
    `(${account.premium_leads_total ?? "n/a"} all-time)`;

  const budgetText =
    `*Demo budget today (UTC):* chat ${budgetLine(budget.chatUsed, env.DEMO_CHAT_DAILY)} · ` +
    `embed ${budgetLine(budget.embedUsed, env.DEMO_EMBED_DAILY)}`;

  const slackText =
    `:newspaper: *HelpFlow daily digest — ${day}*\n` +
    `${tenantLines.join("\n")}\n` +
    `${accountLine}\n` +
    `${budgetText}\n` +
    `Console: ${env.CONSOLE_BASE_URL || ""}`;

  const emailSubject = `[HelpFlow] Daily digest — ${day}`;
  const emailBody =
    `<h3>HelpFlow daily digest — ${day}</h3>` +
    `<ul>${tenants
      .map(
        (t) =>
          `<li><strong>${escapeHtml(t.tenant_name)}</strong> — ` +
          `${t.conversations_24h ?? 0} conversation(s) in 24h · ` +
          `deflection ${pct(t.deflection_rate)} all-time (${t.total_conversations ?? 0} total) · ` +
          `${t.open_escalations ?? 0} open escalation(s)` +
          (t.top_gaps ? `<br/>gaps: ${escapeHtml(t.top_gaps)}` : "") +
          `</li>`,
      )
      .join("")}</ul>` +
    `<p>${escapeHtml(accountLine.replace(/\*/g, ""))}</p>` +
    `<p>${escapeHtml(budgetText.replace(/\*/g, ""))}</p>` +
    (env.CONSOLE_BASE_URL
      ? `<p><a href="${env.CONSOLE_BASE_URL}">Open the console</a></p>`
      : "");

  return { slackText, emailSubject, emailBody };
}

if (typeof $input !== "undefined") {
  const tenants = $("Fetch Digest Stats")
    .all()
    .map((i) => i.json)
    .filter((t) => t.tenant_name);
  const accountItem = $("Fetch Account Stats").first();
  const account = (accountItem && accountItem.json) || {};
  const budgetItem = $input.first();
  const raw = (budgetItem && budgetItem.json) || {};
  const result = Array.isArray(raw.result) ? raw.result : [null, null];
  const budget = {
    chatUsed: result[0] === null || result[0] === undefined ? null : parseInt(result[0], 10) || 0,
    embedUsed: result[1] === null || result[1] === undefined ? null : parseInt(result[1], 10) || 0,
  };
  return [
    {
      json: formatDigest(tenants, account, budget, {
        DEMO_CHAT_DAILY: $env.DEMO_CHAT_DAILY,
        DEMO_EMBED_DAILY: $env.DEMO_EMBED_DAILY,
        CONSOLE_BASE_URL: $env.CONSOLE_BASE_URL,
      }, new Date()),
    },
  ];
}

module.exports = { formatDigest };
